import { OAuth2Auth } from '../auth_credential.js';
import { AuthScheme } from '../auth_schemes.js';
/**
 * Returns the token endpoint for the given auth scheme.
 */
export declare function getTokenEndpoint(authScheme: AuthScheme): string | undefined;
/**
 * Fetches OAuth2 tokens from the endpoint using the given body.
 */
export declare function fetchOAuth2Tokens(endpoint: string, body: URLSearchParams): Promise<OAuth2Auth>;
/**
 * Parses the authorization code from an authorization response URI.
 */
export declare function parseAuthorizationCode(uri: string): string | undefined;
/**
 * Parameters for a Client Credentials token request.
 */
export interface ClientCredentialsParams {
    grantType: 'client_credentials';
    clientId: string;
    clientSecret: string;
}
/**
 * Parameters for an Authorization Code token request.
 */
export interface AuthorizationCodeParams {
    grantType: 'authorization_code';
    clientId: string;
    clientSecret: string;
    code: string;
    redirectUri?: string;
    codeVerifier?: string;
}
/**
 * Parameters for a Refresh Token request.
 */
export interface RefreshTokenParams {
    grantType: 'refresh_token';
    clientId: string;
    clientSecret: string;
    refreshToken: string;
}
/**
 * Parameters for creating an OAuth2 token request body.
 */
export type OAuth2TokenRequestParams = ClientCredentialsParams | AuthorizationCodeParams | RefreshTokenParams;
/**
 * Creates URLSearchParams for an OAuth2 token request.
 */
export declare function createOAuth2TokenRequestBody(params: OAuth2TokenRequestParams): URLSearchParams;
export declare function isTokenExpired(token: OAuth2Auth, leeway?: number): boolean;
